def main():
    conn = sqlite3.connect(str(DB))
    conn.row_factory = sqlite3.Row
    try:
        # 1. order 45 (P46) 내용 교체
        conn.execute(
            "UPDATE sections SET title=?, content=? WHERE proposal_id=? AND order_idx=45",
            (P46_TITLE, P46, PID),
        )
        print("order=45 (P46 KPI) 교체")

        # 2. order 46 (old P47 채널 성장) -> order 49로 shift + 내용을 P50으로 교체
        conn.execute(
            "UPDATE sections SET order_idx=49, title=?, content=? WHERE proposal_id=? AND order_idx=46",
            (P50_TITLE, P50, PID),
        )
        print("order=46 -> 49 (P50 기타 제안 3약속) 교체 및 이동")

        # 3. 신규 insert: order 46, 47, 48, 50
        for oi, title, content in [
            (46, P47_TITLE, P47),
            (47, P48_TITLE, P48),
            (48, P49_TITLE, P49),
            (50, P51_TITLE, P51),
        ]:
            conn.execute(
                """INSERT INTO sections (proposal_id, level, title, order_idx, content, status)
                   VALUES (?, 2, ?, ?, ?, 'pending')""",
                (PID, title, oi, content),
            )
            print(f"order={oi} insert (P{oi + 1})")

        conn.commit()
        print("\n완료 - DB 반영")
    finally:
        conn.close()


if __name__ == "__main__":
    main()
